import Foundation

// Analytics Class
class Analytics {
    func logEvent(_ event: String, data: [String: Any]? = nil) {
        print("Event: \(event)")
        
        if let data = data {
            for (key, value) in data {
                print("\(key): \(value)")
            }
        } else {
            print("Data: nil")
        }
    }
    
    func logError(_ error: Error) {
        print("Error: \(error.localizedDescription)")
        print("Stacktrace: \(error.userInfo)")
    }
}

// API Call Logger
class APILogger {
    let analytics = Analytics()
    
    func logAPIRequest(_ request: URLRequest?) {
        if let request = request {
            let url = request.url?.absoluteString ?? ""
            let method = request.httpMethod ?? ""
            
            print("API Request:")
            print("  URL: \(url)")
            print("  Method: \(method)")
            print("  Headers: \(request.allHTTPHeaderFields ?? [:])")
        } else {
            analytics.logEvent("api_request", data: ["status": "failed"])
        }
    }
    
    func logAPIResponse(_ response: URLResponse?, data: Data?) {
        if let response = response, let data = data {
            print("API Response:")
            print("  Status Code: \(response.statusCode)")
            print("  Headers: \(response.allHeaderFields)")
            print("  Payload: \(String(data: data, encoding: .utf8) ?? "")")
        } else {
            analytics.logEvent("api_response", data: ["status": "failed"])
        }
    }
}

// Example Usage
let apiLogger = APILogger()
func fetchData() {
    let url = URL(string: "https://example.com/api/data")!
    var request = URLRequest(url: url)
    request.httpMethod = "GET"
    
    apiLogger.logAPIRequest(request)
    
    URLSession.shared.dataTask(with: request) { data, response, error in
        if let error = error {
            apiLogger.logError(error)
        }
        
        guard let data = data else { return }
        apiLogger.logAPIResponse(response, data: data)
    }.resume()
}

fetchData()